window.__QUIZ_DATA__=[{"id":"objective>Geography>2011>1","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The scaale of the map in Representative Fraction (RF) is","images":["data:image/png;base64,"],"options":{"A":"1 : 100,000","B":"1 : 200,000","C":"1 : 300,000","D":"1 : 450,000"},"answer":"A","explanation":"The scale of the map in Representive fraction (RF) is 1:100,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>2","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"If the map is reduced to half its original size, the scale will be","images":[],"options":{"A":"1 : 400,000","B":"1 : 200,000","C":"1 : 100,000","D":"1 : 50,000"},"answer":"B","explanation":"If the map is reduced to half its original size, the scale will be 0.5 : 100,000 = 1:200,000     1100000x12=12=1200000=1:200,000","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>3","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"River Eda flows from","images":[],"options":{"A":"Southeast to Northwest","B":"Southwest to Northwest","C":"Northwest to Southwest","D":"Northest to southeast"},"answer":"A","explanation":"River Eda flows from Southeast to Northwest","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>4","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"What is the bearing of Uzen from EDAFA?","images":[],"options":{"A":"320o","B":"210o","C":"170o","D":"130o"},"answer":"B","explanation":"From the map given, we can deduce the bearing of Uzen from EDAFA.        \u21d2 The bearing of Uzen from EDAFA is something greater than 180o, so from the options only 210o is greater than 180o","marks":"1","difficulty":"3"},{"id":"objective>Geography>2011>5","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The settlement of EDAFA is more important than Uzen because of the presence of a","images":[],"options":{"A":"court house","B":"school","C":"market","D":"rest house"},"answer":"B","explanation":"The settlement of EDAFA is more important than Uzen because of the presence of a school","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>6","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the name of the feature marked P on the map?","images":[],"options":{"A":"Cliff","B":"Slope","C":"Knoll","D":"Ridge"},"answer":"C","explanation":"The feature marked P is Knoll  N.B: A knoll is a small mound or rounded hill","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>7","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The highest point on the mapped area is","images":[],"options":{"A":"750m","B":"900m","C":"1100m","D":"1150m"},"answer":"D","explanation":"The highest point on the map is around Alo, and it is 1150m","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>8","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Which part of the map has the lowest elevation?","images":[],"options":{"A":"North West","B":"North East","C":"South West","D":"South East"},"answer":"A","explanation":"The part of the map with the lowest elevation is Northwest   N.B: The elevation  (least) around this region is 100m.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>9","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The main type of vegetation in the North Western part of the map is","images":[],"options":{"A":"shrub","B":"forest","C":"swamp","D":"montane"},"answer":"B","explanation":"The main type of vegetation in the North Western part of the map is forest","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>10","subject":"Geography","year":"2011","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"The South Eastern part of the mapped area is suitable for","images":[],"options":{"A":"lumbering","B":"mining","C":"animal rearing","D":"cement manufacturing"},"answer":"C","explanation":"The South Eastern part of the mapped area is suitable for animal rearing because it is composed mainly of grasslands","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>11","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The solar system comprises","images":[],"options":{"A":"the sun, the earth and pluto","B":"the sun, the earth and the moon","C":"the sun and its nine planets","D":"the sun and the earth"},"answer":"C","explanation":"The solar system comprises of the sun and the nine planets","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>12","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"The angle of difference formed between the True North and magnetic North is known as","images":[],"options":{"A":"magnetic declination","B":"Magnetic differentiation","C":"magnetic variation","D":"magnetic devaluation"},"answer":"A","explanation":"Magnetic declination is the angle of different formed because the true North and Magnetic North      \u03b8 = magnetic declination","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>13","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"If the time in town X on the longitude 15oE is 1.00pm on the Saturday, what will be the time on town Y on longitude 75oW?","images":[],"options":{"A":"11.0 am on Saturday","B":"9.00pm on Saturday","C":"6.00 pm on Saturday","D":"7.00 am on Saturday"},"answer":"D","explanation":"Town x Towny Location long .15oE long .75oW Time 1.00 pm Unknown Day Saturday Unknown      \u21d2 Longitudinal Difference = 15o + 75o = 90o    1o = 4 minutes   15o = 1 hours   90o = x   \u21d2 x = 6 hours     We are to count 6 hours back from 1:00 pm, hence we have 7.00 am on Saturday.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>14","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The mineral content of the upper part of the earth's crust are collectively called the sial because it is composed mainly of","images":[],"options":{"A":"silica and olivine","B":"alumina and olivine","C":"silica and alumina","D":"alumina and vine"},"answer":"C","explanation":"The mineral contents of the upper part of the earth's crust are collectively called the sial because it is composed mainly of silica and alumina","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>15","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The lowest layer of the atmosphere is the","images":[],"options":{"A":"stratosphere","B":"troposphere","C":"thermosphere","D":"exosphere"},"answer":"B","explanation":"The lowest layer of the atmosphere is the troposhere. It is the lower levels of the atmosphere extending from the surface of the Earth or another celestial body up to the tropo pause. It is characterized by connective air movements and a large vertical temperature change.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>16","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is the most abundant in total volume within the atmosphere?","images":[],"options":{"A":"Hydrogen","B":"Argon","C":"Nitrogen","D":"Carbondioxide"},"answer":"C","explanation":"The percentage composition (i.e volume) of Nitrogen is the highest, 78%.     \u21d2 CO2 = 0.03%   O2 = 21.0%   Noble Gases = 0.001%","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>17","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"A rock through which water cannot passed is termed","images":[],"options":{"A":"permeable","B":"porous","C":"sedimentary","D":"impermeable"},"answer":"D","explanation":"A rock through which water cannot pass is termed impermeable. Permeability in geology refers to the ability of a material (usually soil or rock) to transmit fluid through it. When a rock is impermeable, it means that water or other fluids cannot pass through it.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>18","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Use the diagram below to answer question 18 to 20.    The diagram above is a","images":["data:image/png;base64,"],"options":{"A":"dot map","B":"pie chart","C":"flow chart","D":"bar graph"},"answer":"D","explanation":"The diagram given is a bar graph. It is a graph in the form of boxes of different heights, with each box representing a different value or category of data, and the heights representing frequencies","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>19","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"How many people are in village X?","images":["data:image/png;base64,"],"options":{"A":"10","B":"20","C":"35","D":"40"},"answer":"B","explanation":"The frequency corresponding to village X is 1/2 x 40 = 20 Hence there are 20 people in village X","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>20","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The most popular village has","images":["data:image/png;base64,"],"options":{"A":"120 people","B":"95 people","C":"80 people","D":"60 people"},"answer":"B","explanation":"The most populated village is village O with an estimated 95 people","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>21","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the following is the most effective agent of coastal erosion?","images":[],"options":{"A":"Sea currents","B":"Sea Waves","C":"Underground water","D":"Sea tides"},"answer":"B","explanation":"Sea waves are the most effective agent of coastal erosion. They break down rock and sediment along coastlines, reshaping the land. While sea currents, underground water, and sea tides can also contribute to coastal erosion, the constant action of waves against the coastline has the greatest impact.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>22","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Aw in Koppen's classification of climate refers to","images":[],"options":{"A":"Steppe","B":"Tropical","C":"Mediterranean","D":"Polar"},"answer":"B","explanation":"Aw refers to \"The tropical wet and dry or savanna.\"   Others include Af = tropical wet climate   Af = tropical monsoon climate   Bw = Dry arid (Desert)  Bs = dry semiarid (steppe), etc.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>23","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following towns is located in Koppen's Aw climate?","images":[],"options":{"A":"Lagos","B":"Tamale","C":"Algiers","D":"Lome"},"answer":"D","explanation":"Lome town is located in Koppon Aw's climate. Others are not.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>24","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"In areas where folding has occurred oil and natural gas usually collect in","images":[],"options":{"A":"synclines","B":"horst","C":"cuestas","D":"nappes"},"answer":"A","explanation":"Oil and natural gas are usually collected in synclines. A syncline is a concave-upward fold in rock strata","marks":"1","difficulty":"3"},{"id":"objective>Geography>2011>25","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following does not encourage the formation of rainfall?","images":[],"options":{"A":"Converging wind","B":"Ascending wind","C":"Descending wind","D":"Warm wind"},"answer":"C","explanation":"Descending wind does not support the formation of rainfall   NOTE: Descending wind, also known as katabatic wind is the technical name for a drainage wind that carries high-density air from a higher elevation down a slope under the force of gravity.   \u21d2It is a wind which causes dessication, it does not support rainfall.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>26","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Use the diagram below to answer question 26 to 28    The feature marked P is a/an","images":["data:image/png;base64,"],"options":{"A":"waterfall","B":"plunge pool","C":"eroded debris","D":"scree"},"answer":"A","explanation":"The feature marked P is a waterfall. A waterfall is a natural feature where water from a river or stream flows over a vertical drop or a series of steep drops in the course of its flow.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>27","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The feature marked X is a/an","images":["data:image/png;base64,"],"options":{"A":"eroded debris","B":"waterfall","C":"plunge pool","D":"scree"},"answer":"C","explanation":"The feature marked X is a plunge pool. A plunge pool is a deep depression or basin that forms at the base of a waterfall. It is created by the erosive action of the water as it falls from a height, impacting the rock below.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>28","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The feature marked A is a/an","images":["data:image/png;base64,"],"options":{"A":"scree","B":"waterfall","C":"eroded debris","D":"plunge pool"},"answer":"C","explanation":"The feature marked A is an eroded debris. Eroded debris refers to the loose material, such as rocks, soil, sand, and other particles, that has been broken down and carried away by natural processes like water, wind, or ice. Erosion involves the wearing away of the Earth's surface, and the resulting debris is often transported to other locations, where it may be deposited in valleys, rivers, oceans, or at the base of cliffs and mountains.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>29","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"The most permanent physical property of the soil is its","images":[],"options":{"A":"depth","B":"texture","C":"colour","D":"organic matter"},"answer":"B","explanation":"The texture of the soil is its most permanent physical property. Soil texture refers to the size distribution of mineral particles in a soil sample. It is a fundamental property of soils that does not change over time, unlike depth, color, or organic matter, which can vary with weather conditions, erosion, or human activity.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>30","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Desert areas experience high daily range of temperature because","images":[],"options":{"A":"they are generally low-lying","B":"the sky is cloudless","C":"they experience very high atmospheric pressure","D":"the winds blow off-show at night"},"answer":"B","explanation":"Desert areas experience high daily range of temperature because the sky is cloudless. This means the humidity level is low and cannot reduce the hotness of the sun.   Also note that clouds block the sun and cool the air underneath them, which increases the relative humidity of the air. In deserts, the sky has no cloud, so the air is very hot and the relative humidity is low.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2011>31","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following is a warm ocean current?","images":[],"options":{"A":"The Mozambique Current","B":"The Californian Current","C":"The Benguela Current","D":"The West Wind Drift"},"answer":"A","explanation":"The Monzabique current is a warm ocean current   N.B: Warm ocean current  flows away from the equatorial region on the western side of ocean basins.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>32","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Air pollution  is caused by all the following except","images":[],"options":{"A":"evapo-transpiration","B":"fumes from vehicles","C":"discharge of gasses from factories","D":"volcanic eruptions"},"answer":"A","explanation":"Evapo-transpiration is not a cause of air pollution. It is a natural process that involves the transfer of water from the land to the atmosphere by evaporation from the soil and other surfaces and by transpiration from plants. The other options, fumes from vehicles, discharge of gases from factories, and volcanic eruptions, are all sources of air pollution.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>33","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"The acacia tree is commonly found in the","images":[],"options":{"A":"coniferous forest","B":"mediterranean lands","C":"savannah lands","D":"Mangrove forest"},"answer":"C","explanation":"The acacia tree is commonly found in the savannah lands. Savannah lands are characterized by a grassland ecosystem with scattered trees, and the acacia tree is one of the most common types of trees found in these areas. The other options, coniferous forest, mediterranean lands, and Mangrove forest, are not typical habitats for the acacia tree.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>34","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following is the lower atmosphere is of little use to man, plants and animals?","images":[],"options":{"A":"Carbon dioxide","B":"Nitrogen","C":"Oxygen","D":"Argon"},"answer":"D","explanation":"Argon is of little use to man   carbon (iv) oxide \u21d2 Needed by plants for photosynthesis   Oxygen \u21d2 Needed by man/animal for respiration   Hydrogen \u21d2 An important tissue element","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>35","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"The dynamic and interdependent complex interaction of soil, climate and vegetation with its animal population is called","images":[],"options":{"A":"food chain","B":"ecosystem","C":"carbon cycle","D":"hydrological cycle"},"answer":"B","explanation":"The dynamic and inter dependent complex interaction of soil, climate and vegetation with its animal population is called ecosystem","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>36","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A built-up area consisting of a number of towns or cities merged together yet maintaining their individual identities is termed a/an","images":[],"options":{"A":"municipal town","B":"twin city","C":"city centre","D":"conurbation"},"answer":"D","explanation":"A built-up area consisting of a number of towns or cities merged together yet maintaining their individual identities is termed a cornubation","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>37","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following are true of most large cities? I. They have large plantations II. They are capital cities III. They are religious centres IV. They are commercial centres","images":[],"options":{"A":"II and IV","B":"I and III","C":"II and III","D":"I and V"},"answer":"A","explanation":"Large cities are: Capital cities   Commercial centres   N.B: An example of Large cities is Lagos State.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>38","subject":"Geography","year":"2011","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Which of the following is not a plantation crop in West Africa?","images":[],"options":{"A":"Rubber","B":"Wheat","C":"Sugar cane","D":"Coffee"},"answer":"B","explanation":"Plantation crops are typically large-scale monoculture crops that are grown in tropical or subtropical regions. In West Africa, common plantation crops include rubber, sugar cane, and coffee. Wheat, on the other hand, is not a typical plantation crop in West Africa due to the region's climate and soil conditions. Therefore, the correct answer is Wheat.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>39","subject":"Geography","year":"2011","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"The role of transportation in economic development in West Africa include all of the following except","images":[],"options":{"A":"national disintegration","B":"Movement of goods and services","C":"opening up new lands","D":"provision of employment"},"answer":"A","explanation":"The role of transportation in economic development in West Africa does not include:  national disintegration","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>40","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Aluminium is used largely in the","images":[],"options":{"A":"aviation industry","B":"ship building industry","C":"Chemical industry","D":"ceramics industry"},"answer":"A","explanation":"Aluminium is a lightweight, yet strong material. This makes it ideal for use in the aviation industry where weight is a critical factor. It is used in the construction of aircraft bodies and other parts.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>41","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Light industries predominate in West Africa because of","images":[],"options":{"A":"inadequate capital","B":"sparse population","C":"adequate technology","D":"adequate power supply"},"answer":"A","explanation":"Light industries are industries that are usually less capital intensive than heavy industries; and is more consumer oriented than business oriented, as it typically produces another consumer goods.   N.B: Light industries predominate in West Africa because of inadequate capital","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>42","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Possible solutions to the problem of soil erosion in the highlands of West Africa includes the following except","images":[],"options":{"A":"indiscriminate felling of trees","B":"rotational grazing","C":"strip cultivation","D":"planting of shelter belts"},"answer":"A","explanation":"Possible solution to the problem of soil erosion in the highlands of West Africa does not include indiscriminate felling of trees as this further causes soil erosion","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>43","subject":"Geography","year":"2011","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"Which of the following is not a common farming system in West Africa?","images":[],"options":{"A":"Crop rotation","B":"Rotational bush fallowing","C":"Terracing","D":"Subsistence"},"answer":"C","explanation":"Terracing is not a common farming system in West Africa. Terracing is a farming system that is commonly used in mountainous or hilly regions to create flat areas for farming. This method is not common in West Africa because the region is largely flat and does not have the hilly or mountainous landscapes that would require terracing.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>44","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The busiest and most important ocean trade route is","images":[],"options":{"A":"Indian Ocean route","B":"cape route","C":"north Atlantic route","D":"Suez Canal route"},"answer":"C","explanation":"The busiest and most important ocean trade route is the North Atlantic route. This route connects North America and Europe, two of the world's largest economies. It is the most heavily trafficked ocean trade route due to the high volume of goods that are transported between these two continents.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2011>45","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"In which of the following periods is the harmattan dominant in West Africa?","images":[],"options":{"A":"August to October","B":"May to July","C":"November to January","D":"February to April"},"answer":"D","explanation":"Harmattan is a dry and dusty wind which blows from Sahara over the Atlantic coast (South) of West Africa in December, January and february, being a hot wind in some areas and cold in another.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>46","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The dry winds that blow out of the Sahara Desert towards the Southern parts of West Africa is known as","images":[],"options":{"A":"fohn","B":"Sirroco","C":"mistral","D":"harmattan"},"answer":"D","explanation":"The dry winds that blow out of the Sahara Desert towards the Southern parts of West Africa is known as the Harmattan. The Harmattan is a dry and dusty northeasterly trade wind, which blows from the Sahara Desert over West Africa into the Gulf of Guinea.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2011>47","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following types of weathering is common in humid tropical areas?","images":[],"options":{"A":"Exfoliation","B":"Granular disintegration","C":"Hydrolysis","D":"Freeze-thaw"},"answer":"C","explanation":"Hydrolysis is the most common type of weathering in humid tropical areas. Hydrolysis is a chemical process that involves the reaction of water with minerals to form new minerals. In humid tropical areas, the high temperatures and abundant rainfall provide the perfect conditions for hydrolysis to occur.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>48","subject":"Geography","year":"2011","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following countries records the highest annual rainfall?","images":[],"options":{"A":"Liberia","B":"Algeria","C":"Mali","D":"Egypt"},"answer":"A","explanation":"Liberia records the highest annual rainfall among the listed countries. Liberia, located in West Africa, has a tropical climate characterized by heavy rainfall from May to October with a short interlude in mid-July to August. During the remaining months, rainfall is minimal.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>49","subject":"Geography","year":"2011","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"When was the treaty which formally established ECOWAS signed?","images":[],"options":{"A":"July 17th 1970","B":"May 18th 1973","C":"April 18th 1974","D":"May 28th 1975"},"answer":"D","explanation":"The treaty which formally established ECOWAS was signed on May 28th, 1975. This is a historical fact and can be verified from various sources.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2011>50","subject":"Geography","year":"2011","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"In which of the following countries is tourism the leading industry?","images":[],"options":{"A":"Ghana","B":"The Gambia","C":"Liberia","D":"Nigeria"},"answer":"B","explanation":"In The Gambia, tourism is the leading industry. The Gambia is a small West African country known for its diverse ecosystems around the central Gambia River. It is a popular tourist destination, with its economy heavily reliant on tourism.","marks":"1","difficulty":"1"}];